// Function to set the theme on the html element and save to localStorage
function setTheme(theme) {
  document.documentElement.setAttribute('data-bs-theme', theme);
  localStorage.setItem('theme', theme);
}

// Function to handle the switch change event
function switchTheme(event) {
  if (event.target.checked) {
    setTheme('dark');
  } else {
    setTheme('light');
  }
}

// Function to apply the user's saved preference on page load
function applySavedTheme() {
  const savedTheme = localStorage.getItem('theme');
  const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
  
  if (savedTheme) {
    setTheme(savedTheme);
    // Also update the checkbox state to match the saved theme
    document.getElementById('darkModeSwitch').checked = (savedTheme === 'dark');
  } else if (prefersDark) {
    // If no preference saved, use the system preference
    setTheme('dark');
    document.getElementById('darkModeSwitch').checked = true;
  } else {
    setTheme('light');
    document.getElementById('darkModeSwitch').checked = false;
  }
}

// Add event listener to the switch and apply saved theme on load
document.addEventListener('DOMContentLoaded', () => {
  const themeSwitch = document.getElementById('darkModeSwitch');
  if (themeSwitch) {
    themeSwitch.addEventListener('change', switchTheme);
    applySavedTheme();
  }
});
